```typescript
function daysInMonth(month: number, year: number): number {
    if (month === 2) {
        // Check if the year is a leap year
        if ((year % 4 === 0 && year % 100 !== 0) || year % 400 === 0) {
            return 29;
        } else {
            return 28;
        }
